private boolean isRedundantFinallyBlock(Node finallyBlock, int exitType, String labelName) {
  // Check if the finally block contains only redundant exit nodes
  for (Node c = finallyBlock.getFirstChild(); c != null; c = c.getNext()) {
    if (!matchingExitNode(c, exitType, labelName)) {
      return false;
    }
  }
  return true;
}

